fn solve(m: i64, n: i64, waitCost: Vec<Vec<i64>>) -> i64 {
    let m = m as usize;
    let n = n as usize;
    let mut dist = vec![vec![vec![i64::MAX; 2]; n]; m];
    dist[0][0][1] = 1;
    let mut pq = BinaryHeap::new();
    pq.push((1, 0, 0, 1));

    while let Some((cost, i, j, parity)) = pq.pop() {
        if i == m - 1 && j == n - 1 {
            return cost;
        }
        if cost > dist[i][j][parity] {
            continue;
        }
